        <div className="animate-pulse">Completing sign in...</div>
      </div>
    </div>
  ),
})

const routeTree = rootRoute.addChildren([
  indexRoute,
  dealsRoute,
  dealDetailRoute,
  leadsRoute,
  leadDetailRoute,
  companiesRoute,
  companyDetailRoute,
  contactsRoute,
  contactDetailRoute,
  tasksRoute,
  inboxRoute,
  notificationsRoute,
  emailsRoute,
  calendarRoute,
  notesRoute,
  productsRoute,
  salesOrdersRoute,
  salesOrderDetailRoute,
  activitiesRoute,
  reportsRoute,
  authCallbackRoute,
])

const router = createRouter({
  routeTree,
  context: {
    ...TanStackQueryProvider.getContext(),
  },
  defaultPreload: 'intent',
  scrollRestoration: true,
  defaultStructuralSharing: true,
  defaultPreloadStaleTime: 0,
})

declare module '@tanstack/react-router' {
  interface Register {
    router: typeof router
  }
}

const oauthScopes = (
  import.meta.env.VITE_OAUTH2_SCOPES || 'openid profile offline_access'
)
  .split(' ')
  .filter(Boolean)

function isEmbeddedInIframe() {
  try {
    return window.self !== window.top
  } catch {
    return true
  }
}

function resolveAllowedHostOrigins(): Array<string> {
  const origins = new Set<string>()

  const envOrigins = (import.meta.env.VITE_ALLOWED_HOST_ORIGINS || '')
    .split(',')
    .map((origin: string) => origin.trim())
    .filter(Boolean)

  for (const origin of envOrigins) {
    origins.add(origin)
  }

  const locationWithAncestors = window.location as Location &
    Record<string, unknown>
  const ancestorOrigins = locationWithAncestors.ancestorOrigins as
    | { length: number; [index: number]: string }
    | undefined

  if (ancestorOrigins && ancestorOrigins.length > 0) {
    const parentOrigin = ancestorOrigins[0]
    if (parentOrigin) {
      origins.add(parentOrigin)
    }
  }

  if (document.referrer) {
    try {
      origins.add(new URL(document.referrer).origin)
    } catch {
      // Ignore invalid referrer URLs.
    }
  }

  return Array.from(origins)
}

const allowedHostOrigins = resolveAllowedHostOrigins()
const forceMode =
  isEmbeddedInIframe() &&
  new URLSearchParams(window.location.search).get('embedded') === 'true'
    ? 'iframe'
    : undefined

const rootElement = document.getElementById('app')
if (rootElement && !rootElement.innerHTML) {
  const root = ReactDOM.createRoot(rootElement)
  root.render(
    <StrictMode>
      <DocyrusAuthProvider
        apiUrl={import.meta.env.VITE_API_BASE_URL}
        clientId={import.meta.env.VITE_OAUTH2_CLIENT_ID}
        redirectUri={`${window.location.origin}${import.meta.env.VITE_OAUTH2_REDIRECT_URI}`}
        scopes={oauthScopes}
        callbackPath="/auth/callback"
        allowedHostOrigins={
          allowedHostOrigins.length > 0 ? allowedHostOrigins : undefined
        }
        forceMode={forceMode}
      >
        <TanStackQueryProvider.Provider>
          <I18nextProvider i18n={i18n}>
            <I18nDirectionProvider>
              <GlobalDialogProvider persist storageKey="sales-crm-dialogs">
                <RouterProvider router={router} />
              </GlobalDialogProvider>
            </I18nDirectionProvider>
          </I18nextProvider>
        </TanStackQueryProvider.Provider>
      </DocyrusAuthProvider>
    </StrictMode>,
  )
}

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals()

import { QueryClient, QueryClientProvider } from '@tanstack/react-query'

const queryClient = new QueryClient()

export function getContext() {
  return {
    queryClient,
  }
}

export function Provider({ children }: { children: React.ReactNode }) {
  return (
    <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
  )
}

